import base64
import uuid
import zlib
from datetime import datetime, timedelta
from urllib.parse import urlencode
import requests


class SAMLServiceProvider:
    def __init__(self, sp_entity_id, acs_url):
        self.sp_entity_id = sp_entity_id
        self.acs_url = acs_url
    
    def generate_request_id(self):
        return f"__{uuid.uuid4()}"
    
    def get_timestamp(self):
        return datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    def build_authn_request(self, idp_destination_url, user_email=None, relay_state=None):
        request_id = self.generate_request_id()
        issue_instant = self.get_timestamp()
        
        saml_request = f'''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
            xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
            ID="{request_id}"
            Version="2.0"
            IssueInstant="{issue_instant}"
            Destination="{idp_destination_url}"
            AssertionConsumerServiceURL="{self.acs_url}"
            ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
            <saml:Issuer>{self.sp_entity_id}</saml:Issuer>
            <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
        </samlp:AuthnRequest>'''
        
        return saml_request
    
    def build_authn_request_with_user_info(self, idp_destination_url, user_email, user_name=None, custom_attributes=None):
        request_id = self.generate_request_id()
        issue_instant = self.get_timestamp()
        
        extensions = ""
        if user_email or user_name or custom_attributes:
            extensions = '<samlp:Extensions>'
            if user_email:
                extensions += f'<custom:Email>{user_email}</custom:Email>'
            if user_name:
                extensions += f'<custom:Name>{user_name}</custom:Name>'
            if custom_attributes:
                for key, value in custom_attributes.items():
                    extensions += f'<custom:{key}>{value}</custom:{key}>'
            extensions += '</samlp:Extensions>'
        
        saml_request = f'''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
            xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
            xmlns:custom="urn:custom:params"
            ID="{request_id}"
            Version="2.0"
            IssueInstant="{issue_instant}"
            Destination="{idp_destination_url}"
            AssertionConsumerServiceURL="{self.acs_url}"
            ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
            <saml:Issuer>{self.sp_entity_id}</saml:Issuer>
            {extensions}
            <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
        </samlp:AuthnRequest>'''
        
        return saml_request
    
    def encode_saml_request(self, saml_request):
        compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(compressed).decode('utf-8')
        return encoded
    
    def post_saml_request(self, idp_destination_url, user_email=None, user_name=None, custom_attributes=None, relay_state=None):
        if user_email or user_name or custom_attributes:
            saml_request = self.build_authn_request_with_user_info(
                idp_destination_url, 
                user_email, 
                user_name, 
                custom_attributes
            )
        else:
            saml_request = self.build_authn_request(idp_destination_url, user_email, relay_state)
        
        encoded_request = self.encode_saml_request(saml_request)
        
        payload = {
            'SAMLRequest': encoded_request
        }
        
        if relay_state:
            payload['RelayState'] = relay_state
        
        response = requests.post(idp_destination_url, data=payload)
        
        return {
            'status_code': response.status_code,
            'response_text': response.text,
            'saml_request': saml_request,
            'encoded_request': encoded_request
        }
    
